/// {@category Data}
library;

// Package imports:
import 'package:freezed_annotation/freezed_annotation.dart';

// Project imports:
import 'package:baseball_detector_flutter/constants.dart';
import 'package:baseball_detector_flutter/data/models/utils/json_big_int_converter.dart';

part 'plan.freezed.dart';
part 'plan.g.dart';

@freezed
abstract class Plan with _$Plan {
  @JsonSerializable(
    explicitToJson: true,
    fieldRename: Constants.modelFieldRename,
  )
  const factory Plan({
    @Default(null) String? id,
    @Default(null) String? name,
    @Default(null) String? description,
    @Default(null) @JsonBigIntConverter() int? type,
    @Default(null) @JsonBigIntConverter() int? maxBalls,
    @Default(null) @JsonBigIntConverter() int? maxAiCoachs,
    @Default(false) bool isPaid,
    @Default(false) bool isActive,
    @Default(null) DateTime? createdAt, // assumes UTC
    @Default(null) DateTime? updatedAt, // assumes UTC
    @Default(null) dynamic platformConfig,
  }) = _Plan;

  factory Plan.fromJson(Map<String, dynamic> json) => _$PlanFromJson(json);
}

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:gap/gap.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/app_store_plan.dart';
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/utils/date.dart';

enum SubscriptionBadgeType {
  bestValue,
  recommended,
}

class SubscriptionPlanCard extends HookWidget {
  const SubscriptionPlanCard({
    required this.plan,
    required this.badgeType,
    required this.onTap,
    required this.isSelected,
    this.isCurrentPlan = false,
    this.cancelScheduledAt,
    this.downgradeScheduledAt,
    this.downgradePlanName,
    super.key,
  });
  final AppStoreProduct plan;
  final SubscriptionBadgeType? badgeType;
  final VoidCallback? onTap;
  final bool isSelected;
  final bool isCurrentPlan;
  final DateTime? cancelScheduledAt;
  final DateTime? downgradeScheduledAt;
  final String? downgradePlanName;

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);
    final features = getPlanFeatures(plan.planType, context);
    // 現在のプランでキャンセルの予定もダウングレードの予定もない場合
    final isTapEnabled = !(isCurrentPlan &&
        cancelScheduledAt == null &&
        downgradeScheduledAt == null);
    return GestureDetector(
      onTap: isTapEnabled ? onTap : null,
      child: Container(
        decoration: BoxDecoration(
          borderRadius: BorderRadius.circular(16),
          border: Border.all(
            // 現在プランかつキャンセル予定、ダウングレード予定なし: 「現在利用中」スタイル
            // それ以外（キャンセル予定あり含む）は通常の選択/非選択スタイル
            color: isTapEnabled
                ? isSelected
                    ? theme.colorScheme.primary
                    : theme.colorScheme.outline.withValues(alpha: 0.3)
                : theme.colorScheme.primary.withValues(alpha: 0.5),
            width: isSelected ? 2 : 1,
          ),
          color: isTapEnabled
              ? theme.colorScheme.surface
              : theme.colorScheme.primary.withValues(alpha: 0.05),
        ),
        child: Stack(
          children: [
            Padding(
              padding: const EdgeInsets.all(12),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  // プラン名と価格
                  const Gap(20),
                  Row(
                    mainAxisAlignment: MainAxisAlignment.spaceBetween,
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Text(
                        features.planName,
                        style: theme.textTheme.headlineSmall?.copyWith(
                          fontWeight: FontWeight.bold,
                        ),
                      ),
                      Row(
                        crossAxisAlignment: CrossAxisAlignment.end,
                        children: [
                          Text(
                            plan.displayPrice,
                            style: theme.textTheme.headlineMedium?.copyWith(
                              fontWeight: FontWeight.bold,
                            ),
                          ),
                          const Gap(4),
                          Text(
                            context.l10n.subscription_page__per_month_suffix,
                            style: theme.textTheme.bodyMedium?.copyWith(
                              color: theme.colorScheme.onSurfaceVariant,
                            ),
                          ),
                        ],
                      ),
                    ],
                  ),
                  const Gap(12),
                  // プラン詳細情報
                  _buildPlanFeature(
                    icon: Icons.sports_baseball,
                    title: context.l10n.subscription_page__analysis_ball_count,
                    value:
                        '${features.ballCount} ${context.l10n.subscription_page__ball_count}',
                    theme: theme,
                  ),
                  // TODO: AIコーチ実装後に表示
                  // const Gap(4),
                  // _buildPlanFeature(
                  //   icon: Icons.psychology,
                  //   title: context.l10n.subscription_page__ai_coach_usage_count,
                  //   value: features.aiCoachCount,
                  //   theme: theme,
                  // ),
                  // キャンセル/ダウングレード予定の注意書き
                  if (cancelScheduledAt != null ||
                      downgradeScheduledAt != null) ...[
                    const Gap(8),
                    _buildScheduleNotice(context, theme),
                  ],
                ],
              ),
            ),
            // Best value / Recommended バッジ
            if (badgeType != null)
              Positioned(
                top: -1,
                left: -1,
                child: Container(
                  padding:
                      const EdgeInsets.symmetric(horizontal: 12, vertical: 4),
                  decoration: BoxDecoration(
                    color: theme.colorScheme.primary,
                    borderRadius: const BorderRadius.only(
                      topLeft: Radius.circular(16),
                      bottomRight: Radius.circular(16),
                    ),
                  ),
                  child: Text(
                    switch (badgeType) {
                      SubscriptionBadgeType.bestValue =>
                        context.l10n.subscription_page__best_value_badge,
                      SubscriptionBadgeType.recommended =>
                        context.l10n.subscription_page__recommended_badge,
                      _ => '',
                    },
                    style: TextStyle(
                      color: theme.colorScheme.onPrimary,
                      fontSize: 12,
                      fontWeight: FontWeight.bold,
                    ),
                  ),
                ),
              ),
            // 選択中チェックマーク / 現在利用中バッジ（予定の表示は下部の注意書きへ移動）
            if (isCurrentPlan)
              Positioned(
                top: 8,
                right: 8,
                child: Container(
                  padding: const EdgeInsets.symmetric(
                    horizontal: 8,
                    vertical: 4,
                  ),
                  decoration: BoxDecoration(
                    color: theme.colorScheme.primary,
                    borderRadius: BorderRadius.circular(12),
                  ),
                  constraints: const BoxConstraints(maxWidth: 220),
                  child: const _CurrentBadgeWithSchedule(),
                ),
              )
            else if (isSelected)
              Positioned(
                top: 8,
                right: 8,
                child: Container(
                  width: 20,
                  height: 20,
                  decoration: BoxDecoration(
                    color: theme.colorScheme.primary,
                    shape: BoxShape.circle,
                  ),
                  child: Icon(
                    Icons.check,
                    color: theme.colorScheme.onPrimary,
                    size: 16,
                  ),
                ),
              ),
          ],
        ),
      ),

